+using System.Text.RegularExpressions;
+
+namespace DocSummary.Services;
+
+/// <summary>
+/// A simple extractive summarizer that scores sentences by word frequency
+/// and returns the top-ranked ones in their original order.
+/// </summary>
+public partial class ExtractiveSummarizer : IDocumentSummarizer
+{
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
+        "this", "that", "which", "who", "whom", "has", "have", "had", "be",
+        "been", "being", "do", "does", "did", "will", "would", "shall",
+        "should", "may", "might", "can", "could", "not", "no", "as", "if",
+        "then", "than", "so", "up", "out", "about", "into", "over", "after"
+    };
+
+    public string Summarize(string documentText, int maxSentences)
+    {
+        var sentences = SplitSentences(documentText);
+        if (sentences.Count <= maxSentences)
+        {
+            return string.Join(" ", sentences);
+        }
+
+        var wordFrequencies = BuildWordFrequencies(sentences);
+        var scored = sentences
+            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => sentences[s.Index]);
+
+        return string.Join(" ", scored);
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        return SentenceRegex()
+            .Split(text)
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in ExtractWords(sentence))
+            {
+                if (!StopWords.Contains(word))
+                {
+                    freq[word] = freq.GetValueOrDefault(word) + 1;
+                }
+            }
+        }
+        return freq;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
+    {
+        var words = ExtractWords(sentence);
+        if (words.Count == 0) return 0;
+        return words.Sum(w => wordFrequencies.GetValueOrDefault(w)) / (double)words.Count;
+    }
+
+    private static List<string> ExtractWords(string text)
+    {
+        return WordRegex()
+            .Matches(text)
+            .Select(m => m.Value.ToLowerInvariant())
+            .Where(w => w.Length > 1)
+            .ToList();
+    }
